import { takaro, data } from '@takaro/helpers';

const targetName = (data.arguments.target || '').trim();
if (!targetName) {
  await data.player.pm('Usage: /visit <player name>');
} else {
  const search = await takaro.playerOnGameserver.playerOnGameServerControllerSearch({
    filters: { gameServerId: [data.gameServerId], online: [true] },
    search: { name: [targetName] },
    limit: 10,
  });
  const matches = (search.data && search.data.data) || [];
  let match = matches.find((m) => (m.name || '').toLowerCase() === targetName.toLowerCase());
  if (!match && matches.length === 1) match = matches[0];
  if (!match) {
    await data.player.pm(`No unique match for "${targetName}".`);
  } else {
    const targetRes = await takaro.player.playerControllerGetOne(match.playerId);
    const cmdRes = await takaro.gameserver.gameServerControllerExecuteCommand(data.gameServerId, {
      command: `visit ${data.player.platformId} ${targetRes.data.data.platformId}`,
    });
    const result = (cmdRes.data && cmdRes.data.data) || {};
    if (result.success === false) {
      await data.player.pm(result.rawResult || 'Visit failed.');
    } else {
      await data.player.pm(`Teleported to ${match.name}.`);
    }
  }
}

import { takaro, data } from '@takaro/helpers';

const events = await takaro.event.eventControllerSearch({
  filters: {
    eventName: ['player-death'],
    playerId: [data.player.id],
    gameserverId: [data.gameServerId],
  },
  sortBy: 'createdAt',
  sortDirection: 'desc',
  limit: 1,
});

if (events.data.data.length === 0) {
  await data.player.pm('No death recorded yet.');
} else {
  const { x, y, z } = events.data.data[0].meta.position;
  await takaro.gameserver.gameServerControllerExecuteCommand(data.gameServerId, {
    command: `tp ${data.player.platformId} ${x} ${y} ${z}`,
  });
  await data.player.pm('Teleported to your last death.');
}

import { takaro, data } from '@takaro/helpers';

const pog = await takaro.playerOnGameserver.playerOnGameServerControllerGetOne(data.gameServerId, data.player.id);
const { positionX, positionY, positionZ } = pog.data.data;

const existing = await takaro.variable.variableControllerSearch({
  filters: {
    key: ['home'],
    moduleId: [data.module.moduleId],
    gameServerId: [data.gameServerId],
    playerId: [data.player.id],
  },
});

await Promise.all(existing.data.data.map(v => takaro.variable.variableControllerDelete(v.id)));

await takaro.variable.variableControllerCreate({
  key: 'home',
  value: JSON.stringify({ x: positionX, y: positionY, z: positionZ }),
  moduleId: data.module.moduleId,
  gameServerId: data.gameServerId,
  playerId: data.player.id,
});

await data.player.pm(`Home set at ${Math.round(positionX)}, ${Math.round(positionY)}, ${Math.round(positionZ)}.`);

import { takaro, data } from '@takaro/helpers';

const existing = await takaro.variable.variableControllerSearch({
  filters: {
    key: ['home'],
    moduleId: [data.module.moduleId],
    gameServerId: [data.gameServerId],
    playerId: [data.player.id],
  },
});

const home = existing.data.data[0];

if (!home) {
  await data.player.pm('No home set. Use /sethome to save your current location.');
} else {
  const { x, y, z } = JSON.parse(home.value);
  const id = data.player.platformId.replace('dayz:', '');
  await takaro.gameserver.gameServerControllerExecuteCommand(data.gameServerId, {
    command: `tp ${id} ${x} ${y} ${z}`,
  });
  await data.player.pm(`Teleported to your home at ${Math.round(x)}, ${Math.round(y)}, ${Math.round(z)}.`);
}
